output.sparql:
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX wd: <http://www.wikidata.org/entity/>
SELECT(?height / 100 AS ?height_in_m) WHERE {
  wd:Q799589 wdt:P527 ?subevent .
  {
    ?subevent wdt:P1545 ?medalStatement .
    ?medalStatement wdt:P1544 ?athlete .
  } UNION {
    ?subevent wdt:P1546 ?medalStatement .
    ?medalStatement wdt:P1544 ?athlete .
  } UNION {
    ?subevent wdt:P1547 ?medalStatement .
    ?medalStatement wdt:P1544 ?athlete .
  }
  ?athlete wdt:P2048 ?height .
  FILTER(isNumeric(?height) && ?height > 0)
}
ORDER BY DESC(?height)
LIMIT 1
OFFSET 1

